export interface IResult<D, E = Error> {
  code: number;
  msg: string;
  data?: D;
  error?: E;
  success: boolean;
}
export function toResult<T, E>(data: T, code: number, msg, error: E): IResult<T, E> {
  return {
    code,
    data,
    msg: msg || error ? "错误! " : "成功! ",
    error,
    success: !!error,
  };
}
